import{_ as e,o as r,c as a,a7 as i}from"./chunks/framework.BgApuQ2e.js";const n="/images/odd-things-odd-places-intro/Odd-Trips-INTRO-FEATURE2-1024x694.png",o="/images/odd-things-odd-places-intro/pinit_fg_en_rect_gray_20.png",T=JSON.parse('{"title":"Odd Things in Odd Places: Intro","description":"","frontmatter":{"title":"Odd Things in Odd Places: Intro","titleZh":"奇地奇观:序言","date":"2014-07-06T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html","slug":"odd-things-odd-places-intro"},"headers":[],"relativePath":"posts/odd-things-odd-places-intro.md","filePath":"posts/odd-things-odd-places-intro.md","lastUpdated":1782886257000}'),d={name:"posts/odd-things-odd-places-intro.md"};function s(p,t,l,h,m,c){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="奇地奇观-序言-·-odd-things-in-odd-places-intro" tabindex="-1">奇地奇观:序言 · Odd Things in Odd Places: Intro <a class="header-anchor" href="#奇地奇观-序言-·-odd-things-in-odd-places-intro" aria-label="Permalink to &quot;奇地奇观:序言 · Odd Things in Odd Places: Intro&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html</a> · 2014-07-06</p></blockquote><p>几个月前,五月版的 Tim 灵感突现。</p><p>“你猜怎么着才叫酷?”五月 Tim 自言自语,“把六月 Tim、七月 Tim 和八月 Tim 一个人扔到一堆他谁都不认识、跟谁都说不上话的地方,然后他们就能写一个超棒的博客系列出来!”</p><p>五月 Tim 简直按捺不住。</p><p>有一些显而易见的问题——六月、七月、八月 Tim 到这些地方到底要干嘛,博客内容写什么,这几位 Tim 整个夏天都拖着一个包过日子会是什么感受,他们要怎么一边回复邮件、维持正常生活,一边手忙脚乱地兑现五月 Tim 对读者的承诺、撑起五月 Tim 吹出去的牛?</p><p>幸运的是,这些问题都不是五月 Tim 的问题。“哦他们会搞定的,”五月 Tim 躺在床上啜着早咖啡,悠然遐想。</p><p>唯一需要处理的问题是,他到底要把其他 Tim 们送到哪里去。反正这事对他基本没啥影响,他索性拉一大批匿名的 Wait But Why 读者进来一起策划,给 WBW 的邮件订阅者发了一份候选国家的投票。那些读者也不太在乎,把未来的几位 Tim 送去了俄罗斯、日本、尼日利亚、伊拉克和格陵兰。管他妈的,为啥不呢。</p><p>五月 Tim 买了机票,办了签证,打了几针疫苗,然后就继续过他的生活,把手一拍,啥事没有。</p><p>然后有趣的事情发生了。五月 Tim 永远消失了,现在我,七月 Tim,身处俄罗斯正中间,手里只有五月 Tim 留下的这几条指示:“行,就这事写一大篇博客,要写得好、要有原创性,另外去一趟西伯利亚因为这样有意思,还要找一个跟你年纪差不多的人跟他换一天的生活因为我跟大家说了你要这么干,但你得自己搞清楚为啥要这么干,因为我也没想明白。哦对了预算基本没有你自己想办法。好啦我得走了,我有一大堆这趟旅行的『不做规划』要忙,因为我就是不打算用宝贵的五月来帮你处理你现在的处境,我就是这种人。祝你好运!”</p><p>于是就有了这个「怪地方的怪旅行 (Odd Trips in Odd Places)」系列,从现在起一直持续到八月底。</p><p>在这五个地方,我会尽可能多地和当地人聊天,尽量深入了解当地文化,并钻进社会最古怪的角落里看看那里都在发生什么。而且在某个时刻,我会找一个人跟他换一天的生活,看看一个跟我完全不一样的人过着什么样的日子。</p><p>每一段旅程结束时,我会写一篇长文把发生的一切记录下来。我还带了一台摄像机,如果条件允许,我也会加入视频和照片。</p><p>最后,我会在每个国家随机采访 50 个人,问他们这样一个问题:<em>如果你有一个阿拉丁神灯里的精灵,可以帮你实现任意三个愿望,你会许什么愿?</em> 我也不完全确定会得到什么样的答案,但我觉得看看不同国家的人回答有何不同,应该会挺有意思。等我在五个地方都做完采访之后,再专门写一篇聊这个。</p><p>计划就是这样。</p><p>全局是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/07/Odd-Trips-INTRO-FEATURE2.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Odd Trips INTRO - FEATURE"></a></p><p><strong>现在都写完了,以下是这几篇文章:</strong><a href="https://waitbutwhy.com/2014/07/russia-what-you-didnt-know.html" target="_blank" rel="noreferrer">俄罗斯 (Russia)</a><a href="https://waitbutwhy.com/2014/07/japan-and-how-i-failed-to-figure-it-out.html" target="_blank" rel="noreferrer">日本 (Japan)</a><a href="https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html" target="_blank" rel="noreferrer">尼日利亚 (Nigeria)</a><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">伊拉克 (Iraq)</a><a href="https://waitbutwhy.com/2014/09/but-what-about-greenland.html" target="_blank" rel="noreferrer">格陵兰 (Greenland)</a></p><p><a href="https://waitbutwhy.com/2014/09/genie-question.html" target="_blank" rel="noreferrer">我在这五个国家都问过人们的神灯问题</a></p><p>还有一次是,<a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">朝鲜 (North Korea)</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html&amp;description=Odd%20Things%20in%20Odd%20Places:%20Intro" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p>',22)])])}const _=e(d,[["render",s]]);export{T as __pageData,_ as default};
